messages.content:
Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "properties": {
    "income": {
      "type": "object",
      "properties": {
        "line1": {
          "type": "object",
          "properties": {
            "a": {
              "type": "number",
              "description": "Total amount from Form W-2 box 1."
            },
            "b": {
              "type": "number",
              "description": "Household employee wages not reported on Form W-2."
            },
            "h": {
              "type": "number",
              "description": "Other earned income."
            },
            "z": {
              "type": "number",
              "description": "Total of lines 1a through 1h"
            }
          }
        },
        "line3": {
          "type": "object",
          "properties": {
            "a": {
              "type": "number",
              "description": "Qualified dividends."
            },
            "b": {
              "type": "number",
              "description": "Ordinary dividends."
            }
          }
        },
        "line4": {
          "type": "object",
          "properties": {
            "a": {
              "type": "number",
              "description": "IRA distributions."
            }
          }
        },
        "line5": {
          "type": "object",
          "properties": {
            "a": {
              "type": "number",
              "description": "Pensions and annuities."
            }
          }
        },
        "line6": {
          "type": "object",
          "required": [
            "a",
            "b",
            "c"
          ],
          "properties": {
            "a": {
              "type": "number",
              "description": "Social security benefits."
            },
            "b": {
              "type": "number",
              "description": "Taxable amount."
            },
            "c": {
              "type": "boolean",
              "description": "Whether the taxpayer elected to use the lump sum election method. Return false unless box is checked."
            }
          }
        },
        "line7": {
          "type": "number",
          "description": "Capital gain or loss"
        },
        "line8": {
          "type": "number",
          "description": "Additional income from Schedule 1"
        },
        "line9": {
          "type": "number",
          "description": "Taxpayer total income"
        },
        "line10": {
          "type": "number",
          "description": "Adjustments to income from Schedule 1"
        },
        "line11": {
          "type": "number",
          "description": "Taxpayer adjusted gross income"
        },
        "line12": {
          "type": "number",
          "description": "Standard deduction or itemized deductions"
        },
        "line13": {
          "type": "number",
          "description": "Qualified business income deduction "
        },
        "line14": {
          "type": "number",
          "description": "Total of lines 12 and 13"
        },
        "line15": {
          "type": "number",
          "description": "Taxpayer taxable income"
        }
      },
      "description": "Income items from Form 1040"
    },
    "address": {
      "type": "object",
      "required": [
        "address1",
        "address2",
        "city",
        "state",
        "zipCode"
      ],
      "properties": {
        "city": {
          "type": "string"
        },
        "state": {
          "type": "string"
        },
        "zipCode": {
          "type": "string"
        },
        "address1": {
          "type": "string",
          "description": "Address line one. Excludes Suites / Apartment numbers."
        },
        "address2": {
          "type": "string",
          "description": "Address line two"
        }
      }
    },
    "taxPeriod": {
      "type": "object",
      "properties": {
        "taxDateStart": {
          "type": "string",
          "description": "Month and day tax year start (ex: 1/01)"
        }
      }
    },
    "dependents": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "firstName",
          "lastName",
          "ssn",
          "relationship",
          "childTaxCredit",
          "otherCredit"
        ],
        "properties": {
          "ssn": {
            "type": "string",
            "description": "Dependent social security number. Return in the following format: 123-45-6789"
          },
          "lastName": {
            "type": "string"
          },
          "firstName": {
            "type": "string"
          },
          "otherCredit": {
            "type": "boolean",
            "description": "Does the dependent qualify for other credit. Return false unless box is checked"
          },
          "relationship": {
            "type": "string"
          },
          "childTaxCredit": {
            "type": "boolean",
            "description": "Does the dependent qualify for child tax credit. Return false unless box is checked"
          }
        }
      },
      "description": "List of dependents and their information. Return null if there are no dependents."
    },
    "ageBlindness": {
      "type": "object",
      "required": [
        "bornBeforeJanuary",
        "blind",
        "spouseBornBeforeJanuary",
        "spouseBlind"
      ],
      "properties": {
        "blind": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Taxpayer is blind. Return false unless box is checked."
        },
        "spouseBlind": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Spouse is blind. Return false unless box is checked."
        },
        "bornBeforeJanuary": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Taxpayer born before January 2, 1960. Return false unless box is checked."
        },
        "spouseBornBeforeJanuary": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Spouse born before January 2, 1960. Return false unless box is checked."
        }
      },
      "description": "Taxpayer and Spouse age and blindess classification."
    },
    "filingStatus": {
      "type": "object",
      "required": [
        "single",
        "HOH",
        "MFJ",
        "MFS",
        "QSS",
        "nonResident"
      ],
      "properties": {
        "HOH": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Head of household. Return false unless box is checked."
        },
        "MFJ": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Married filing jointly. Return false unless box is checked."
        },
        "MFS": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Married filing separately. Return false unless box is checked."
        },
        "QSS": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Qualifying surviving spouse. Return false unless box is checked."
        },
        "single": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Single. Return false unless box is checked."
        },
        "nonResident": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "If treating a nonresident alien or dual-status alien spouse as a U.S. resident for the entire tax year. Return false unless box is checked."
        }
      },
      "description": "Taxpayer filing status."
    },
    "personalInfo": {
      "type": "object",
      "properties": {
        "ssn": {
          "type": "string",
          "description": "Primary social security number. Always return in the following format: 123-45-6789"
        },
        "firstName": {
          "type": "string",
          "description": "Taxpayer first name. Exclude middle initial."
        }
      }
    },
    "digitalAssets": {
      "type": "boolean",
      "description": "Receive, sell, exchange, or otherwise dispose of digital assets"
    },
    "standardDeductions": {
      "type": "object",
      "required": [
        "youAreDependent",
        "spouseIsDependent",
        "spouseItemizes"
      ],
      "properties": {
        "spouseItemizes": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Spouse itemizes on a separate return. Return false unless box is checked."
        },
        "youAreDependent": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Someone can claim you as a dependent. Return false unless box is checked."
        },
        "spouseIsDependent": {
          "not": {
            "type": "null"
          },
          "type": "boolean",
          "description": "Someone can claim your spouse as a dependent. Return false unless box is checked."
        }
      },
      "description": "Standard Deductions."
    }
  }
}
